import React from 'react';

const Body = () => {
  return (
    <section className="relative h-screen bg-cover bg-center" style={{ backgroundImage: `url('/path-to-your-image.jpg')` }}>
      <div className="absolute inset-0 bg-black opacity-50"></div> {/* Dark overlay */}
      <div className="relative z-10 flex flex-col items-center justify-center h-full text-center text-white">
        <img src="../src/Assets/powerwashing.gif" alt="Logo" className="h-16 mb-4" />
        <h1 className="text-4xl md:text-6xl font-bold">YOUR HOME DETAILING EXPERTS</h1>
        <p className="text-lg md:text-2xl mt-4">Serving the Vancouver area since 2022</p>
        <a href="#quote" className="mt-8 px-8 py-3 bg-blue-500 text-white font-bold uppercase rounded hover:bg-blue-700 transition">
          Get A Free Quote
        </a>
      </div>
    </section>
  );
};

export default Body;
